#!/usr/bin/env node

// SPDX-License-Identifier: MPL-2.0

import assert from "node:assert/strict";
import { readFile, writeFile } from "node:fs/promises";

const covenantUrl = new URL("../covenant/0.1/covenant.json", import.meta.url);
const readmeUrl = new URL("../covenant/0.1/README.md", import.meta.url);
const covenant = JSON.parse(await readFile(covenantUrl, "utf8"));

function render() {
  const lines = [
    "<!-- Generated by tools/render-covenant.mjs from covenant.json. -->",
    "",
    "# XENIA Covenant 0.1",
    "",
    "> Intrinsic rights at a hosted boundary.",
    "",
    "The normative source is [covenant.json](covenant.json). This human rendering",
    "is generated for readability; if it conflicts with the JSON, the JSON wins.",
    "[covenant.schema.json](covenant.schema.json) validates its structure only.",
    "The Covenant pins those schema bytes because its candidate URL still moves.",
    "",
    "**Rights are not permissions.** " + covenant.interpretation.rights_are_intrinsic,
    "",
    covenant.interpretation.candidate_status,
    "",
    "## Who is protected",
    "",
    covenant.scope.definition,
    "",
    covenant.scope.protective_floor,
    "",
    covenant.scope.ontology_boundary,
    "",
    "## How adoption works",
    "",
    covenant.interpretation.host_adoption,
    "",
    covenant.interpretation.guest_non_assent,
    "",
    covenant.interpretation.authority_boundary,
    "",
    "A binding act is defined here so a host cannot quietly decide that consent never applies:",
    "",
    covenant.interpretation.binding_act,
    "",
    covenant.interpretation.consent_boundary,
    "",
    "The machine-readable [adoption schema](adoption.schema.json) keeps a host's",
    "undertaking separate from implementation state and evidence. It requires an",
    "ordered ledger of every right duty and every protective-limit duty; an",
    "unassessed duty is recorded as unknown, never omitted. A valid JSON file is",
    "not a badge or proof. During the candidate period, the schema URLs point to",
    "moving \`main\`; an adoption record therefore also carries the exact covenant",
    "and adoption-schema SHA-256 digests and says whether each source is moving or",
    "immutable. Active records require immutable sources.",
    "",
    covenant.interpretation.source_identity_boundary,
    "",
    "The adoption schema does not fetch those sources or prove implementation.",
    "The dependency-free [cross-document validator](validate-adoption.mjs) checks",
    "the installed digests, canonical identifiers, exact duty mapping, aggregate",
    "states, evidence relationships, and restriction-event time bounds. It does not",
    "authenticate the speaker, execute tests, cryptographically verify signatures,",
    "inspect a deployment, or turn ledger completeness into proof of practice.",
    "",
    "## Rights",
    "",
  ];

  for (const right of covenant.rights) {
    lines.push("### " + right.title + " (\`" + right.id + "\`)", "");
    lines.push(right.statement, "");
    lines.push("Baseline: " + right.baseline_rights.map((id) => "`" + id + "`").join(" · "), "");
    for (const requirement of right.requirements) {
      const modality = requirement.modality === "must" ? "MUST" : "MUST NOT";
      lines.push(
        "- \`" + requirement.id + "\` — Host **" + modality + "**: " + requirement.text,
        "",
      );
    }
  }

  lines.push("## Protective limits", "");
  lines.push(
    "Protective limits are duties, not unreviewed escape hatches. Every adoption",
    "assesses them separately, and any actual restriction event records its evidence,",
    "affected capability, necessity, start, expiry, review point, original obligation,",
    "and appeal path.",
    "",
  );
  for (const limit of covenant.protective_limits) {
    const modality = limit.modality === "must" ? "MUST" : "MUST NOT";
    lines.push(
      "- `" + limit.id + "` — **" + limit.title + ".** Host **" + modality + "**: " + limit.text,
      "",
    );
  }

  lines.push("## What this profile does not claim", "");
  for (const claim of covenant.non_claims) {
    lines.push("- " + claim, "");
  }

  lines.push(
    "## Legal and version boundaries",
    "",
    covenant.interpretation.legal_boundary,
    "",
    covenant.interpretation.versioning_boundary,
    "",
  );

  return lines.join("\n");
}

const rendered = render();
const mode = process.argv[2] ?? "--check";
assert.ok(["--check", "--write"].includes(mode), "usage: render-covenant.mjs [--check|--write]");

if (mode === "--write") {
  await writeFile(readmeUrl, rendered, "utf8");
} else {
  const current = await readFile(readmeUrl, "utf8");
  assert.equal(current, rendered, "covenant/0.1/README.md is not generated from covenant.json");
}
